[ApiController]
[Route("api/[controller]")]
public class ProxyController : ControllerBase
{
    private readonly HttpClient _httpClient;

    public ProxyController(IHttpClientFactory httpClientFactory)
    {
        _httpClient = httpClientFactory.CreateClient();
    }

    [HttpGet("{path}")]
    public async Task<IActionResult> Get(string path)
    {
        var request = new HttpRequestMessage(HttpMethod.Get, $"https://target-endpoint.com/{path}");
        var response = await _httpClient.SendAsync(request);

        response.EnsureSuccessStatusCode();
        return new ObjectResult(await response.Content.ReadAsStringAsync());
    }

    [HttpPost("{path}")]
    public async Task<IActionResult> Post(string path)
    {
        var request = new HttpRequestMessage(HttpMethod.Post, $"https://target-endpoint.com/{path}");
        var response = await _httpClient.SendAsync(request);

        response.EnsureSuccessStatusCode();
        return new ObjectResult(await response.Content.ReadAsStringAsync());
    }

